#include <stdio.h>
#include <string.h>

char* largestOdd(char* s) {
    int len = strlen(s);
    int ind = -1;
    for (int i = len - 1; i >= 0; i--) {
        if ((s[i] - '0') % 2 == 1) {
            ind = i;
            break;
        }
    }
    if (ind == -1) return "";
    int i = 0;
    while (i <= ind && s[i] == '0') i++;
    return strncpy(s + i, s + i, ind - i + 1);
}

int main() {
    char s[] = "1234567890";
    printf("Largest odd number: %s\n", largestOdd(s));
    return 0;
}

